# 1. รับค่าอายุ (ต้องครอบด้วย int() เพื่อเปลี่ยนตัวหนังสือเป็นตัวเลข)
age = int(input("กรุณาใส่อายุของคุณ: "))

# 2. ใช้ if-else ตัดสินใจ
if age >= 18:
    print("คุณคือ: ผู้ใหญ่")
    print("ยินดีด้วย คุณทำใบขับขี่ได้แล้ว!")
else:
    print("คุณคือ: เด็ก")
    print("ไปกินนมแล้วเข้านอนซะนะ")

print("--- จบโปรแกรม ---")
